#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

int main() {
    int N;
    scanf("%d", &N);
    uint64_t F[1 << N], G[1 << N], H[1 << N];
    for (int i = 0; i < (1 << N); i++) {
        scanf("%llu", &F[i]);
    }
    for (int i = 0; i < (1 << N); i++) {
        scanf("%llu", &G[i]);
    }
    for (int i = 0; i < (1 << N); i++) {
        scanf("%llu", &H[i]);
    }
    uint64_t R[1 << N];
    for (int X = 0; X < (1 << N); X++) {
        R[X] = 0;
        for (int A = 0; A < (1 << N); A++) {
            for (int B = 0; B < (1 << N); B++) {
                for (int C = 0; C < (1 << N); C++) {
                    if ((X & (~A & ~B & ~C)) == 0) {
                        R[X] = (R[X] + F[A] * G[B] % MOD * H[C]) % MOD;
                    }
                }
            }
        }
    }
    uint64_t sum = 0;
    for (int i = 0; i < (1 << N); i++) {
        sum = (sum + R[i]) % MOD;
    }
    printf("%llu\n", sum);
    return 0;
}

